import React, { useCallback, useEffect } from "react";
import { MultiSelect } from "primereact/multiselect";
import KitsContainer from "../../helpers/FormContainer";
import type { IMultiSelect } from "@lmb-it/kitsconcerto-types";
import { AiOutlineClose } from "react-icons/ai";
import { checkKeys } from "../helper";
import { useKitsTheme } from "../../../contexts/Theme";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useSelectBase } from "../hooks/useSelectBase";

const KitsMultiSelect = ({ className, ref, ...rawProps }: IMultiSelect) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('MultiSelect', rawProps, 'Select');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        disabled,
        isFloatedLabel,
        rightAddon,
        leftAddon,
        required,
        errors,
        invalid,
        attached,
        placeholder,
        virtualScroll,
        label,
        inputSize,
        helperText,
        emptyFilterMessage,
        selectionLimit,
        localProps,
        hideError,
        withFilter,
        loading,
        showClear,
        valueMode,
        containerStyle,
    } = props;

    const { list, keys, onChange, selectedValue, childrenKey, labelKey, valueKey } = useSelectBase();

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    useEffect(() => {
        checkKeys(list, labelKey, !childrenKey ? valueKey : undefined);
    }, [list]);

    const handleChange = useCallback((e: any) => {
        if (selectionLimit && Array.isArray(e?.value) && e.value.length > selectionLimit) {
            return;
        }
        onChange && onChange(e);
    }, [selectionLimit, onChange]);

    const Element = (
        <MultiSelect
            emptyFilterMessage={emptyFilterMessage}
            value={selectedValue}
            onChange={handleChange}
            disabled={disabled}
            loading={loading}
            showClear={showClear}
            options={typeof list !== "function" ? list : []}
            placeholder={placeholder}
            {...keys}
            filter={withFilter !== false}
            clearIcon={<AiOutlineClose />}
            selectionLimit={selectionLimit}
            virtualScrollerOptions={virtualScroll}
            display={valueMode === "comma" ? "comma" : (localProps?.maxSelectedLabels ? undefined : "chip")}
            maxSelectedLabels={localProps?.maxSelectedLabels}
            className="w-full"
            style={{ borderRadius: 0, border:'none' }}
            pt={{
                root: {
                    style: {
                        borderRadius: 0,
                        border:'none',
                       ...resolvedRootStyle,
                        ...resolvedThemeStyle
                    },
                },
                input:{
                  style:{
                      borderRadius: 0,
                      border:'none',
                      height:'100%'
                  }
                },
                label:{
                    style:{
                        marginTop:3
                    }
                },
                filterInput:{
                    style:{
                        borderRadius: 0,
                        border:'none'
                    }
                },
                item: ({ context }: any) => context?.selected ? {
                    style: { backgroundColor: primaryColor, color: 'white' }
                } : context?.focused ? {
                    style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
                } : undefined,
                token: {
                    style: {
                        backgroundColor: `color-mix(in srgb, ${primaryColor} 15%, transparent)`,
                        color: primaryColor,
                    }
                },
                headerCheckbox: {
                    box: ({ context }: any) => ({
                        style: {
                            borderColor: context?.checked ? primaryColor : borderColor,
                            backgroundColor: context?.checked ? primaryColor : 'transparent',
                        }
                    }),
                    icon: {
                        style: { color: 'white' }
                    }
                },
                checkbox: {
                    box: ({ context }: any) => ({
                        style: {
                            borderColor: context?.checked ? primaryColor : borderColor,
                            backgroundColor: context?.checked ? primaryColor : 'transparent',
                        }
                    }),
                    icon: {
                        style: { color: 'white' }
                    }
                },
            }}
            {...(localProps ? localProps : {})}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsMultiSelect;
